  "inlineSchema": "// schema.prisma\n// Lifestyle Organiser — Postgres schema (Prisma 7)\n// Run: npx prisma migrate dev --name merge-reminders-into-events\n\ngenerator client {\n  provider = \"prisma-client\"\n  output   = \"../generated/prisma\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\n// ---------- USERS & HOUSEHOLDS ----------\n\nmodel User {\n  id           String     @id @default(cuid())\n  email        String     @unique\n  name         String?\n  passwordHash String?\n  household    Household? @relation(fields: [householdId], references: [id])\n  householdId  String?\n  createdAt    DateTime   @default(now())\n\n  eventsCreated Event[]         @relation(\"EventCreator\")\n  eventInvites  EventAttendee[]\n  recipes       Recipe[]\n}\n\nmodel Household {\n  id        String           @id @default(cuid())\n  name      String\n  users     User[]\n  events    Event[]\n  recipes   Recipe[]\n  watchlist WatchlistEntry[]\n}\n\n// ---------- EVENTS (colour-coded calendar — reminders are events too) ----------\n\nmodel Event {\n  id          String          @id @default(cuid())\n  title       String\n  description String?\n  startAt     DateTime\n  endAt       DateTime?\n  allDay      Boolean         @default(false)\n  location    String?\n  eventType   EventType       @relation(fields: [eventTypeId], references: [id])\n  eventTypeId String\n  household   Household       @relation(fields: [householdId], references: [id])\n  householdId String\n  creator     User            @relation(\"EventCreator\", fields: [creatorId], references: [id])\n  creatorId   String\n  attendees   EventAttendee[]\n\n  // Reminder-style fields — set these to make an event behave as a reminder\n  // (e.g. \"Car Insurance Renewal\"): recurring, with a lead-time \"due soon\" window.\n  // leadTimeDays stays nullable at the DB level (no @default here) — the event\n  // FORM should default the input to 0 (opt-out design: new events show on the\n  // Reminders page unless this is manually cleared to null, e.g. for \"Weekend Away\").\n  recurrence          Recurrence @default(NONE)\n  leadTimeDays        Int? // null = excluded from Reminders page; 0+ = included, due-soon window in days\n  remindMinutesBefore Int? // for same-day nudges on regular events, if ever needed\n\n  createdAt DateTime @default(now())\n}\n\nenum Recurrence {\n  NONE\n  MONTHLY\n  QUARTERLY\n  YEARLY\n}\n\nmodel EventType {\n  id     String  @id @default(cuid())\n  name   String // e.g. \"Weekend Away\", \"Appointment\", \"Insurance\", \"Bill\"\n  color  String // hex code — drives calendar colour-coding\n  events Event[]\n}\n\nmodel EventAttendee {\n  id      String @id @default(cuid())\n  event   Event  @relation(fields: [eventId], references: [id], onDelete: Cascade)\n  eventId String\n  user    User   @relation(fields: [userId], references: [id])\n  userId  String\n\n  @@unique([eventId, userId])\n}\n\n// ---------- RECIPES ----------\n\nmodel Recipe {\n  id          String       @id @default(cuid())\n  title       String\n  description String?\n  imageUrl    String?\n  servings    Int?\n  prepMinutes Int?\n  cookMinutes Int?\n  tags        String[]\n  ingredients Ingredient[]\n  method      String? // single multi-line text field, pasted in — not a repeatable Step model\n  household   Household    @relation(fields: [householdId], references: [id])\n  householdId String\n  author      User         @relation(fields: [authorId], references: [id])\n  authorId    String\n  createdAt   DateTime     @default(now())\n}\n\nmodel Ingredient {\n  id       String           @id @default(cuid())\n  recipe   Recipe           @relation(fields: [recipeId], references: [id], onDelete: Cascade)\n  recipeId String\n  name     String // e.g. \"Sugar\", \"Lemon\", \"Milk\"\n  amount   Float? // supports decimals, e.g. 1.5 — null if the ingredient has no quantity (rare)\n  unit     MeasurementUnit? // null = no unit, e.g. \"1 lemon\" rather than \"1 whole lemon\"\n  order    Int              @default(0)\n}\n\nenum MeasurementUnit {\n  TSP\n  TBSP\n  G\n  ML\n  LITRE\n  PINT\n  OZ\n  LB\n}\n\n// ---------- WATCHLIST ----------\n\nmodel WatchlistEntry {\n  id          String          @id @default(cuid())\n  name        String // show/movie title\n  source      WatchlistSource @relation(fields: [sourceId], references: [id])\n  sourceId    String\n  season      Int? // nullable — movies/one-offs may not have a season\n  episode     Int?\n  status      WatchStatus     @default(TO_WATCH)\n  household   Household       @relation(fields: [householdId], references: [id])\n  householdId String\n  createdAt   DateTime        @default(now())\n  updatedAt   DateTime        @updatedAt // auto-updates whenever any field on the row changes\n}\n\nenum WatchStatus {\n  TO_WATCH\n  WATCHING\n  WATCHED\n}\n\nmodel WatchlistSource {\n  id      String           @id @default(cuid())\n  name    String           @unique // e.g. \"Netflix\", \"Apple TV\", \"IP Stream\", \"Prime\", \"Terrestrial\"\n  entries WatchlistEntry[]\n}\n",
